// Cloudflare Worker that integrates with third-party APIs (SendGrid for email, Stripe for payments)

addEventListener("fetch", event => {
  event.respondWith(handleRequest(event.request))
})

async function handleRequest(request) {
  // API authentication using SendGrid's API key
  const apiKey = "YOUR_SENDGRID_API_KEY"
  const url = new URL(request.url)
  if (url.pathname === "/api/sendgrid") {
    const authHeader = request.headers.get("Authorization")
    if (!authHeader || !authHeader.startsWith("Bearer " + apiKey)) {
      return new Response("Unauthorized", { status: 401 })
    }
  }

  // API authentication using Stripe's API key
  const stripeApiKey = "YOUR_STRIPE_API_KEY"
  if (url.pathname === "/api/stripe") {
    const authHeader = request.headers.get("Authorization")
    if (!authHeader || !authHeader.startsWith("Bearer " + stripeApiKey)) {
      return new Response("Unauthorized", { status: 401 })
    }
  }

  // Handle errors from third-party APIs
  try {
    const response = await fetch(request)
    if (response.status >= 400) {
      return new Response("Error " + response.status, { status: 500 })
    }
    return response
  } catch (error) {
    return new Response("Internal Server Error", { status: 500 })
  }
}